import java.util.Arrays;

class Solution {
    public int minFallingPathSum(int[][] grid) {
        int n = grid.length;
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int minVal = Integer.MAX_VALUE;
                for (int k = 0; k < n; k++) {
                    if (k == j) continue;
                    minVal = Math.min(minVal, grid[i - 1][k]);
                }
                grid[i][j] += minVal;
            }
        }
        return Arrays.stream(grid[n - 1]).min().getAsInt();
    }
}
